+:root {
+  --tc-bg: #f6f3ed;
+  --tc-surface: #fffdf8;
+  --tc-surface-muted: #e7e1d6;
+  --tc-text: #171a1c;
+  --tc-text-soft: #6d706c;
+  --tc-border: #c9c1b4;
+  --tc-trust: #46594f;
+  --tc-action: #b08a4a;
+  --tc-info: #607d8b;
+  --tc-danger: #a85f4f;
+  --tc-radius-card: 8px;
+  --tc-radius-control: 4px;
+}
+
+* {
+  box-sizing: border-box;
+}
+
+body {
+  margin: 0;
+  color: var(--tc-text);
+  font-family: Georgia, "Times New Roman", serif;
+  background:
+    linear-gradient(90deg, rgb(23 26 28 / 4%) 1px, transparent 1px),
+    linear-gradient(rgb(23 26 28 / 4%) 1px, transparent 1px),
+    var(--tc-bg);
+  background-size: 44px 44px;
+}
+
+button,
+input {
+  font: inherit;
+}
+
+.preview-shell {
+  width: min(1180px, calc(100% - 32px));
+  margin: 0 auto;
+  padding: 18px 0 56px;
+}
+
+.topbar {
+  display: grid;
+  grid-template-columns: 1fr auto 1fr;
+  align-items: center;
+  gap: 24px;
+  padding: 12px 0;
+  border-bottom: 1px solid var(--tc-border);
+}
+
+.brand,
+nav a {
+  color: inherit;
+  text-decoration: none;
+}
+
+.brand {
+  display: inline-flex;
+  align-items: center;
+  gap: 10px;
+  font-family: Arial, sans-serif;
+  font-weight: 700;
+}
+
+.brand-mark {
+  display: grid;
+  width: 34px;
+  height: 34px;
+  place-items: center;
+  color: var(--tc-surface);
+  background: var(--tc-text);
+  border-radius: 5px;
+  font-size: 0.78rem;
+}
+
+nav {
+  display: flex;
+  gap: 18px;
+  color: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+  font-size: 0.82rem;
+}
+
+.ghost-button,
+.primary-button,
+.search-panel button {
+  border: 0;
+  border-radius: var(--tc-radius-control);
+  cursor: pointer;
+}
+
+.ghost-button {
+  justify-self: end;
+  padding: 9px 13px;
+  color: var(--tc-text);
+  background: transparent;
+  border: 1px solid var(--tc-border);
+}
+
+.hero {
+  display: grid;
+  grid-template-columns: minmax(0, 1.05fr) minmax(320px, 0.95fr);
+  gap: clamp(28px, 5vw, 72px);
+  align-items: center;
+  min-height: 590px;
+  padding: 56px 0 32px;
+}
+
+.eyebrow,
+.card-label {
+  margin: 0 0 12px;
+  color: var(--tc-trust);
+  font-family: Arial, sans-serif;
+  font-size: 0.75rem;
+  font-weight: 700;
+  letter-spacing: 0.12em;
+  text-transform: uppercase;
+}
+
+h1,
+h2,
+h3,
+p {
+  margin-top: 0;
+}
+
+h1 {
+  max-width: 760px;
+  margin-bottom: 18px;
+  font-size: clamp(3.1rem, 8vw, 7.2rem);
+  line-height: 0.93;
+  letter-spacing: -0.04em;
+}
+
+h2 {
+  font-size: clamp(2rem, 5vw, 4.2rem);
+  line-height: 1;
+  letter-spacing: -0.035em;
+}
+
+h3 {
+  margin-bottom: 8px;
+  font-size: 1.35rem;
+  line-height: 1.1;
+}
+
+.lede {
+  max-width: 620px;
+  color: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+  font-size: 1.1rem;
+}
+
+.search-panel {
+  display: grid;
+  grid-template-columns: 1fr 1fr auto;
+  gap: 1px;
+  max-width: 810px;
+  margin-top: 32px;
+  overflow: hidden;
+  border: 1px solid var(--tc-border);
+  border-radius: var(--tc-radius-card);
+  background: var(--tc-border);
+}
+
+.search-panel label {
+  display: grid;
+  gap: 7px;
+  padding: 15px;
+  background: var(--tc-surface);
+}
+
+.search-panel span {
+  color: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+  font-size: 0.72rem;
+  text-transform: uppercase;
+  letter-spacing: 0.08em;
+}
+
+.search-panel input {
+  width: 100%;
