+  border: 0;
+  outline: 0;
+  background: transparent;
+}
+
+.search-panel button,
+.primary-button {
+  padding: 0 18px;
+  color: var(--tc-surface);
+  background: var(--tc-action);
+  font-family: Arial, sans-serif;
+  font-weight: 700;
+}
+
+.hero-proof {
+  display: grid;
+  gap: 14px;
+}
+
+.graph-card,
+.contractor-card,
+.showcase-card,
+.status-card {
+  border: 1px solid var(--tc-border);
+  border-radius: var(--tc-radius-card);
+  background: rgb(255 253 248 / 88%);
+  box-shadow: 0 22px 70px rgb(23 26 28 / 9%);
+}
+
+.graph-card {
+  padding: 24px;
+}
+
+.graph-card svg {
+  width: 100%;
+  height: auto;
+}
+
+.graph-card path {
+  fill: none;
+  stroke: var(--tc-border);
+  stroke-width: 2;
+}
+
+.graph-card text {
+  fill: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+  font-size: 12px;
+}
+
+.node.trust,
+.status.verified {
+  fill: var(--tc-trust);
+  background: var(--tc-trust);
+}
+
+.node.action,
+.status.pending {
+  fill: var(--tc-action);
+  background: var(--tc-action);
+}
+
+.node.info,
+.status.neutral {
+  fill: var(--tc-info);
+  background: var(--tc-info);
+}
+
+.node.dark {
+  fill: var(--tc-text);
+}
+
+.status.danger {
+  background: var(--tc-danger);
+}
+
+.trust-strip {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 1px;
+  overflow: hidden;
+  border: 1px solid var(--tc-border);
+  border-radius: var(--tc-radius-card);
+  background: var(--tc-border);
+}
+
+.trust-strip span {
+  padding: 14px;
+  background: var(--tc-surface-muted);
+  color: var(--tc-text);
+  font-family: Arial, sans-serif;
+  font-size: 0.82rem;
+  font-weight: 700;
+}
+
+.section-head {
+  max-width: 720px;
+  margin: 24px 0;
+}
+
+.card-grid {
+  display: grid;
+  grid-template-columns: 1fr 1.1fr 0.8fr;
+  gap: 18px;
+}
+
+.contractor-card,
+.status-card {
+  padding: 20px;
+}
+
+.card-topline {
+  display: flex;
+  justify-content: space-between;
+  align-items: center;
+  gap: 16px;
+  margin-bottom: 18px;
+}
+
+.badge {
+  display: inline-flex;
+  align-items: center;
+  gap: 7px;
+  width: fit-content;
+  padding: 6px 9px;
+  border: 1px solid var(--tc-border);
+  border-radius: 999px;
+  color: var(--tc-text);
+  background: var(--tc-surface);
+  font-family: Arial, sans-serif;
+  font-size: 0.72rem;
+  font-weight: 700;
+}
+
+.badge.verified {
+  color: var(--tc-trust);
+}
+
+.badge.brass {
+  color: var(--tc-action);
+}
+
+.badge-dot,
+.status {
+  display: inline-block;
+  width: 8px;
+  height: 8px;
+  border-radius: 50%;
+  background: var(--tc-trust);
+}
+
+.distance,
+.muted,
+.card-note,
+.status-card li {
+  color: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+}
+
+.proof-list {
+  display: grid;
+  grid-template-columns: repeat(3, 1fr);
+  gap: 1px;
+  margin: 22px 0;
+  border: 1px solid var(--tc-border);
+  background: var(--tc-border);
+}
+
+.proof-list div {
+  padding: 13px;
+  background: var(--tc-bg);
+}
+
+.proof-list strong {
+  display: block;
+  margin-bottom: 2px;
+  font-size: 1.45rem;
+}
+
+.proof-list span {
+  display: block;
+  color: var(--tc-text-soft);
+  font-family: Arial, sans-serif;
+  font-size: 0.72rem;
+}
+
+.card-note {
+  margin-bottom: 18px;
+}
+
+.primary-button {
+  width: 100%;
+  min-height: 42px;
+}
+
+.showcase-card {
+  overflow: hidden;
+}
+
+.showcase-media {
+  min-height: 250px;
+  background:
+    linear-gradient(90deg, rgb(23 26 28 / 46%) 0 50%, rgb(23 26 28 / 4%) 50%),
+    linear-gradient(135deg, #cabda9, #f4efe6 48%, #8f9b91);
+}
+
+.before-after {
+  display: grid;
+  grid-template-columns: 1fr 1fr;
+  height: 250px;
+  align-items: end;
+}
+
+.before-after span {
+  padding: 16px;
+  color: var(--tc-surface);
+  font-family: Arial, sans-serif;
+  font-size: 0.75rem;
+  font-weight: 700;
+  letter-spacing: 0.08em;
+  text-transform: uppercase;
+}
+
+.before-after span:last-child {
+  color: var(--tc-text);
+  text-align: right;
+}
+
+.showcase-body {
+  padding: 19px;
+}
+
+.status-card ul {
+  display: grid;
+  gap: 12px;
+  padding: 0;
+  margin: 0;
+  list-style: none;
+}
+
+.status-card li {
+  display: flex;
+  align-items: center;
+  gap: 10px;
+}
+
+.palette {
+  display: grid;
+  grid-template-columns: repeat(4, 1fr);
+  gap: 12px;
+  margin-top: 32px;
+}
+
+.swatch {
+  min-height: 112px;
+  display: flex;
+  flex-direction: column;
+  justify-content: space-between;
+  padding: 14px;
+  border: 1px solid var(--tc-border);
+  border-radius: var(--tc-radius-card);
+  font-family: Arial, sans-serif;
+  font-weight: 700;
+}
+
+.swatch code {
+  font-weight: 400;
+}
+
+.graphite {
+  background: #171a1c;
+  color: #fffdf8;
+}
+
+.plaster {
+  background: #f6f3ed;
+}
+
+.limestone {
+  background: #e7e1d6;
+}
+
+.mortar {
+  background: #c9c1b4;
+}
+
+.oxide {
+  background: #46594f;
+  color: #fffdf8;
+}
+
+.brass {
+  background: #b08a4a;
+  color: #fffdf8;
+}
+
+.slate {
+  background: #607d8b;
+  color: #fffdf8;
+}
+
+.clay {
+  background: #a85f4f;
+  color: #fffdf8;
+}
+
+@media (max-width: 860px) {
+  .topbar,
+  .hero,
+  .card-grid,
+  .palette,
+  .search-panel {
+    grid-template-columns: 1fr;
+  }
+
+  nav {
+    display: none;
+  }
+
+  .ghost-button {
+    justify-self: start;
+  }
+
+  .hero {
+    min-height: auto;
+  }
+
+  .trust-strip,
+  .proof-list {
+    grid-template-columns: 1fr;
+  }
+}
